import java.util.HashSet;
import java.util.Set;

class Solution {
    public boolean pairSumExists(int[] nums, int target) {
        Set<Integer> seen = new HashSet<>();
        for (int num : nums) {
            if (seen.contains(target - num)) {
                return true;
            }
            seen.add(num);
        }
        return false;
    }
}

